import{_ as t,o,c as r,a3 as n}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"85. Flexible Working Arrangements","description":"","frontmatter":{"title":"85. Flexible Working Arrangements","eba":"Biomedical Engineers 2025-2028","topics":["leave","family-violence-leave","employment","flexible-work"]},"headers":[],"relativePath":"ebas/biomedical-engineers/workplace-rights/85-flexible-working-arrangements.md","filePath":"ebas/biomedical-engineers/workplace-rights/85-flexible-working-arrangements.md"}'),s={name:"ebas/biomedical-engineers/workplace-rights/85-flexible-working-arrangements.md"};function a(i,e,l,p,g,h){return o(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="_85-flexible-working-arrangements" tabindex="-1">85. Flexible Working Arrangements <a class="header-anchor" href="#_85-flexible-working-arrangements" aria-label="Permalink to &quot;85. Flexible Working Arrangements&quot;">​</a></h1><p>Other entitlements relevant to family and domestic violence can be found at <a href="/eba/ebas/biomedical-engineers/leave/56-family-violence-leave.html">clause 56</a> - Family Violence Leave.</p><p><strong>85.1</strong> The Act entitles a specified Employee to request flexible working arrangements in specified circumstances.</p><p><strong>85.2</strong> A specified Employee is a:</p><p><strong>(a)</strong> full-time or part-time Employee with at least 12 months continuous service; or</p><p><strong>(b)</strong> casual Employee (as defined by subclause 20.1) who have been employed on a regular and systematic basis, and who has been employed on that basis for a sequence of periods of employment during a period of at least 12 months, and has a reasonable expectation of continuing employment by the Employer on a regular and systematic basis.</p><p><strong>85.3</strong> The specified circumstances are if the Employee:</p><p><strong>(a)</strong> is pregnant;</p><p><strong>(b)</strong> is the parent, or has responsibility for the care, of a child who is of school age or younger;</p><p><strong>(c)</strong> is a carer within the meaning of the Carer Recognition Act 2010 caring for someone who has a disability, a medical condition (including a terminal or chronic illness), a mental illness or is frail or aged;</p><p><strong>(d)</strong> has a disability;</p><p><strong>(e)</strong> is 55 or older;</p><p><strong>(f)</strong> is experiencing family and domestic violence; or</p><p><strong>(g)</strong> provides care or support to a member of the Employee&#39;s Immediate Family, who requires care or support because the member is experiencing family and domestic violence.</p><p><strong>85.4</strong> Making a request</p><p><strong>(a)</strong> A specified Employee may make a request to the Employer for a change in working arrangements relating to the circumstances at subclause 85.3.</p><p><strong>(b)</strong> A request for a flexible work arrangement includes (but is not limited to) a request to work part-time upon return to work after taking leave for the birth or adoption of a child to assist the Employee to care for the child (which may, for example, include a reduction in existing part-time hours).</p><p><strong>(c)</strong> Changes in working arrangements may include but are not limited to hours of work, patterns of work (including not being available to perform on-call for afterhours duty), and location of work.</p><p><strong>(d)</strong> The request by the Employee must be in writing, set out the change sought and reasons for the change.</p><p><strong>85.5</strong> Responding to the request</p><p><strong>(a)</strong> The Employer must give the Employee a written response to the request within 21 days.</p><p><strong>(b)</strong> If the Employer cannot grant the request in full, the Employer may refuse the request only if:</p><p><strong>(i)</strong> the Employer has: <strong>(A)</strong> discussed the request with the Employee; and <strong>(B)</strong> genuinely tried to reach an agreement with the Employee about making changes to the Employee’s working arrangements to accommodate the Employee&#39;s circumstances;</p><p><strong>(ii)</strong> the Employer and the Employee have not reached such an agreement;</p><p><strong>(iii)</strong> the Employer has had regard to the consequences of the refusal for the Employee; and</p><p><strong>(iv)</strong> the refusal is on Reasonable Business Grounds. Note: The specific circumstances of the employer, including the nature and size of the enterprise carried on by the employer, are relevant to whether the employer has reasonable business grounds for refusing a request. For example, if the employer has only a small number of employees, there may be no capacity to change the working arrangements of other employees to accommodate the request (see subclause 4.15(b)).</p><p><strong>(c)</strong> An Employee or Employer may choose to be represented at a meeting under clause 85.5(b)(i)(A) by a representative including a Union or employer organisation.</p><p><strong>(d)</strong> The response must:</p><p><strong>(i)</strong> state that the Employer grants the request;</p><p><strong>(ii)</strong> if, following discussion between the Employer and Employee, the Employer and Employee agree to a change to the Employee’s working arrangements that differs from that set out in the request – set out the agreed change; or</p><p><strong>(iii)</strong> state that the Employer refuses the request.</p><p><strong>(e)</strong> Where the Employer refuses the request, the written response must also include:</p><p><strong>(i)</strong> details of the reasons for the refusal;</p><p><strong>(ii)</strong> the Employers particular business grounds for refusal and an explanation of how these grounds apply to the Employee’s request;</p><p><strong>(iii)</strong> either: <strong>(A)</strong> set out the changes (other than the requested change) in the Employee’s working arrangements that would accommodate, to any extent, the circumstances of the Employee and that the Employer would be willing to make; or <strong>(B)</strong> state that there are no such changes; and</p><p><strong>(iv)</strong> set out the effect of subclause 85.6, including if a dispute is referred to the Commission.</p><p><strong>85.6</strong> Dispute Resolution The dispute resolution procedure in the Agreement will apply to any grievance/dispute arising in relation to a request for flexible working arrangements.</p><p>Plain language terms: flex work, flexible hours, WFH.</p>',38)])])}const u=t(s,[["render",a]]);export{c as __pageData,u as default};
